import{_ as e,c as a,o as r,a4 as t}from"./chunks/framework.OpyvxaCo.js";const b=JSON.parse('{"title":"快速开始","description":"","frontmatter":{"sidebar_position":1},"headers":[],"relativePath":"zh/joinus/index.md","filePath":"zh/joinus/index.md","lastUpdated":1711637073000}'),o={name:"zh/joinus/index.md"},s=t('<h1 id="快速开始" tabindex="-1">快速开始 <a class="header-anchor" href="#快速开始" aria-label="Permalink to &quot;快速开始&quot;">​</a></h1><p>如果您在使用 RSSHub 过程中遇到了问题或者有建议改进，我们很乐意听取您的意见！您可以通过 Pull Request 来提交您的修改。无论您对 Pull Request 的使用是否熟悉，我们都欢迎不同经验水平的开发者参与贡献。如果您不懂编程，也可以通过 <a href="https://github.com/DIYgod/RSSHub/issues" target="_blank" rel="noreferrer">报告错误</a> 的方式来帮助我们。</p><h2 id="参与讨论" tabindex="-1">参与讨论 <a class="header-anchor" href="#参与讨论" aria-label="Permalink to &quot;参与讨论&quot;">​</a></h2><p><a href="https://t.me/rsshub" target="_blank" rel="noreferrer"><img src="https://img.shields.io/badge/chat-telegram-brightgreen.svg?logo=telegram&amp;style=for-the-badge" alt="Telegram 群组"></a> <a href="https://github.com/DIYgod/RSSHub/issues" target="_blank" rel="noreferrer"><img src="https://img.shields.io/github/issues/DIYgod/RSSHub?color=bright-green&amp;logo=github&amp;style=for-the-badge" alt="GitHub Issues"></a></p><h2 id="开始之前" tabindex="-1">开始之前 <a class="header-anchor" href="#开始之前" aria-label="Permalink to &quot;开始之前&quot;">​</a></h2><p>要制作一个 RSS 订阅，您需要结合使用 Git、HTML、JavaScript、jQuery 和 Node.js。</p><p>如果您对它们不是很了解，但想要学习它们，以下是一些好的资源：</p><ul><li><a href="https://developer.mozilla.org/zh-CN/docs/Web/JavaScript#%E6%95%99%E7%A8%8B" target="_blank" rel="noreferrer">MDN Web Docs 上的 JavaScript 指南</a></li><li><a href="https://www.w3schools.com" target="_blank" rel="noreferrer">W3Schools</a></li><li><a href="https://www.codecademy.com/learn/learn-git" target="_blank" rel="noreferrer">Codecademy 上的 Git 课程</a></li></ul><p>如果您想查看其他开发人员如何使用这些技术来制作 RSS 订阅的示例，您可以查看 <a href="https://github.com/DIYgod/RSSHub/tree/master/lib/routes" target="_blank" rel="noreferrer">我们的代码库</a> 中的一些代码。</p><h2 id="提交新的-rsshub-规则" tabindex="-1">提交新的 RSSHub 规则 <a class="header-anchor" href="#提交新的-rsshub-规则" aria-label="Permalink to &quot;提交新的 RSSHub 规则&quot;">​</a></h2><p>如果您发现一个网站没有提供 RSS 订阅，您可以使用 RSSHub 制作一个 RSS 规则。RSS 规则是一个短小的 Node.js 程序代码（以下简称 “路由”），它告诉 RSSHub 如何从网站中提取内容并生成 RSS 订阅。通过制作新的 RSS 路由，您可以帮助让您喜爱的网站的内容被更容易访问和关注。</p><p>在您开始编写 RSS 路由之前，请确保源站点没有提供 RSS。一些网页会在 HTML 头部中包含一个 type 为 <code>application/atom+xml</code> 或 <code>application/rss+xml</code> 的 link 元素来指示 RSS 链接。</p><p>这是在 HTML 头部中看到 RSS 链接可能会长成这样：<code>&lt;link rel=&quot;alternate&quot; type=&quot;application/rss+xml&quot; href=&quot;http://example.com/rss.xml&quot; /&gt;</code>。如果您看到这样的链接，这意味着这个网站已经有了一个 RSS 订阅，您不需要为它制作一个新的 RSS 路由。</p><h3 id="开始" tabindex="-1">开始 <a class="header-anchor" href="#开始" aria-label="Permalink to &quot;开始&quot;">​</a></h3><p>在本指南中，您将学习从头制作一个新的 RSS 路由的方法。我们将涵盖从设置开发环境到提交代码到 RSSHub 仓库的所有内容。到本指南结束时，您将能够为不提供 RSS 的网站制作自己的 RSS 订阅源。</p><p><a href="/zh/joinus/new-rss/prerequisites">准备好了吗？点这里开始学习！</a></p><h2 id="提交新的-rsshub-radar-规则" tabindex="-1">提交新的 RSSHub Radar 规则 <a class="header-anchor" href="#提交新的-rsshub-radar-规则" aria-label="Permalink to &quot;提交新的 RSSHub Radar 规则&quot;">​</a></h2><h3 id="开始之前-1" tabindex="-1">开始之前 <a class="header-anchor" href="#开始之前-1" aria-label="Permalink to &quot;开始之前&quot;">​</a></h3><p>建议您在开始之前，在浏览器中下载并安装 RSSHub Radar。</p><p>安装 RSSHub Radar 后，打开设置并切换到 “规则列表” 选项页。然后滚动到页面底部，您会看到一个文本框。在这里，您可以使用您的新规则替换旧规则以进行调试。</p><p><a href="/zh/joinus/new-radar">开始吧！</a></p><p><a href="https://chrome.google.com/webstore/detail/rsshub-radar/kefjpfngnndepjbopdmoebkipbgkggaa" target="_blank" rel="noopener noreferrer"><img src="https://storage.googleapis.com/web-dev-uploads/image/WlD8wC6g8khYWPJUsQceQkhXSlv1/UV4C4ybeBTsZt43U4xis.png" alt="Get RSSHub Radar for Chromium" style="height:58px;"></a><a href="https://addons.mozilla.org/firefox/addon/rsshub-radar/" target="_blank" rel="noopener noreferrer"><img src="https://blog.mozilla.org/addons/files/2020/04/get-the-addon-fx-apr-2020.svg" alt="Get Get RSSHub Radar for Firefox" style="height:58px;"></a><a href="https://microsoftedge.microsoft.com/addons/detail/rsshub-radar/gangkeiaobmjcjokiofpkfpcobpbmnln" target="_blank" rel="noopener noreferrer"><img src="https://wsrv.nl/?url=https://upload.wikimedia.org/wikipedia/commons/f/f7/Get_it_from_Microsoft_Badge.svg" alt="Get RSSHub Radar for Edge" style="height:58px;"></a><a href="https://apps.apple.com/us/app/rsshub-radar/id1610744717" target="_blank" rel="noopener noreferrer"><img src="https://developer.apple.com/news/images/download-on-the-app-store-badge.png" alt="Get RSSHub Radar for Safari" style="height:58px;"></a></p>',22),l=[s];function i(h,p,n,d,u,c){return r(),a("div",null,l)}const g=e(o,[["render",i]]);export{b as __pageData,g as default};
